parameters.query:
INSERT INTO digital_twin.ingestion_runs (source_id, run_key, status)
VALUES ('usgs-earthquakes', $1, 'running')
ON CONFLICT (source_id, run_key) DO UPDATE SET status = 'running', error_message = NULL;

parameters.jsCode:
// Regional bbox, widened ~3° beyond the visual bbox because earthquakes
// relevant to the corridor originate well outside city limits.
const BBOX = { west: -64.0, south: -36.5, east: -57.0, north: -29.5 };
const fc = $input.first().json;
const rows = [];
for (const f of fc.features ?? []) {
  const [lon, lat, depthKm] = f.geometry.coordinates;
  if (lon < BBOX.west || lon > BBOX.east || lat < BBOX.south || lat > BBOX.north) continue;
  rows.push({
    source_id: 'usgs-earthquakes',
    layer: 'earthquakes',
    external_ref: f.id,
    observed_at: new Date(f.properties.time).toISOString(),
    lon, lat,
    name: f.properties.place ?? 'Earthquake',
    values: { magnitude: f.properties.mag, depth_km: depthKm, place: f.properties.place },
    run_key: $execution.id,
  });
}
// IMPORTANT: an empty result is a valid, expected outcome for this region.
return rows.length ? rows.map(r => ({ json: r })) : [{ json: { empty: true, run_key: $execution.id } }];

parameters.query:
INSERT INTO digital_twin.observations (source_id, layer, external_ref, observed_at, lon, lat, values)
VALUES ($1, $2, $3, $4::timestamptz, $5, $6, $7::jsonb)
ON CONFLICT (source_id, layer, external_ref, observed_at) DO NOTHING;

UPDATE digital_twin.ingestion_runs
SET status = 'error', finished_at = now(), error_message = $2
WHERE source_id = 'usgs-earthquakes' AND run_key = $1;
